function solve(s: string): number {
    const n = s.length;
    const countC: number[] = new Array(n + 1).fill(0);
    const countT: number[] = new Array(n + 1).fill(0);

    // Count 'C' and 'T' from the end to the start
    for (let i = n - 1; i >= 0; i--) {
        countC[i] = countC[i + 1] + (s[i] === 'C' ? 1 : 0);
        countT[i] = countT[i + 1] + (s[i] === 'T' ? 1 : 0);
    }

    let maxCount = 0;

    // Iterate through each possible position to insert 'L'
    for (let i = 0; i <= n; i++) {
        // Count 'L' before the insertion point
        let lCount = 0;
        for (let j = 0; j < i; j++) {
            if (s[j] === 'L') {
                lCount++;
            }
        }
        // Count 'C' and 'T' after the insertion point
        const cCount = countC[i];
        const tCount = countT[i];
        // Total number of 'LCT' sequences with insertion at position i
        const total = lCount * cCount * tCount;
        maxCount = Math.max(maxCount, total);
    }

    return maxCount;
}
